// Pega as legendas do node "Processar o retorno da IA"
const dadosIA = $('Processar o retorno da IA1').item.json;
const legendaInstagram = dadosIA.legenda_instagram || '';
const legendaLinkedin = dadosIA.legenda_linkedin || '';
const legendaX = dadosIA.legenda_x || '';

// Pega as URLs das imagens do node Merge
const mergeData = $input.all();

// DEBUG: Vamos ver o que está vindo
console.log('Total de itens recebidos:', mergeData.length);
console.log('Estrutura do primeiro item:', JSON.stringify(mergeData[0]?.json, null, 2));

// Extrai as URLs - os nodes "Gera URL de download" criam o campo com nomes específicos
const imagem1_url = mergeData[0]?.json?.imagem1_url || '';
const imagem2_url = mergeData[1]?.json?.imagem2_url || '';
const imagem3_url = mergeData[2]?.json?.imagem3_url || '';
const imagem4_url = mergeData[3]?.json?.imagem4_url || '';
const imagem5_url = mergeData[4]?.json?.imagem5_url || '';
const imagem6_url = mergeData[5]?.json?.imagem6_url || '';

// DEBUG: Vamos ver as URLs extraídas
console.log('URLs extraídas:');
console.log('imagem1_url:', imagem1_url);
console.log('imagem2_url:', imagem2_url);
console.log('imagem3_url:', imagem3_url);
console.log('imagem4_url:', imagem4_url);
console.log('imagem5_url:', imagem5_url);
console.log('imagem6_url:', imagem6_url);

// Remove possíveis formatações markdown das legendas
const legendaInstagramLimpa = legendaInstagram.replace(/```|markdown/g, '').trim();
const legendaLinkedinLimpa = legendaLinkedin.replace(/```|markdown/g, '').trim();
const legendaXLimpa = legendaX.replace(/```|markdown/g, '').trim();

// Cria data formatada em português BR com timezone de São Paulo (GMT-3)
const agora = new Date();
const opcoes = {
  timeZone: 'America/Sao_Paulo',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
};
const dataFormatadaBR = new Intl.DateTimeFormat('pt-BR', opcoes).format(agora);
// Resultado: "10/12/2025, 21:47:48" - vamos remover a vírgula
const dataFormatada = dataFormatadaBR.replace(',', '');

// Retorna tudo formatado para inserir no Sheets
return [{
  json: {
    id_post: dadosIA.id_post,
    Titulo: dadosIA.titulo,
    Legenda_Instagram: legendaInstagramLimpa,
    Legenda_LinkedIn: legendaLinkedinLimpa,
    legendaX: legendaXLimpa,
    Status: 'Aguardando Aprovação',
    imagem1_url: imagem1_url,
    imagem2_url: imagem2_url,
    imagem3_url: imagem3_url,
    imagem4_url: imagem4_url,
    imagem5_url: imagem5_url,
    imagem6_url: imagem6_url,
    data_criacao: dataFormatada
  }
}];

// --- Captura o retorno da IA ---
const items = $input.all();
if (!items || items.length === 0) {
  throw new Error("⚠️ Nenhum retorno da IA encontrado.");
}

let resultado = null;
for (const item of items) {
  let output = item.json.output || item.json.text || '';
  if (!output) continue;

  // Remove possíveis blocos Markdown
  output = output.replace(/```json|```/g, '').trim();

  try {
    resultado = JSON.parse(output);
    break; // Se parseou com sucesso, sai do loop
  } catch (err) {
    console.log('Erro ao parsear JSON:', err.message);
  }
}

if (!resultado) {
  throw new Error('❌ Não foi possível extrair JSON válido da resposta da IA');
}

// --- Valida estrutura ---
if (!resultado.textos_imagens || !resultado.queries_unsplash || !resultado.legenda_instagram || !resultado.legenda_linkedin || !resultado.legenda_x) {
  throw new Error('❌ JSON retornado está incompleto');
}

// --- Extrai textos para array simples (compatível com seu HTML) ---
const textos_para_html = [
  resultado.textos_imagens.imagem_1.texto_principal,
  resultado.textos_imagens.imagem_2.texto_principal,
  resultado.textos_imagens.imagem_3.texto_principal,
  resultado.textos_imagens.imagem_4.texto_principal,
  resultado.textos_imagens.imagem_5.texto_principal,
  resultado.textos_imagens.imagem_6.texto_principal
];

// --- Extrai queries para array simples ---
const queries = [
  resultado.queries_unsplash.query_imagem_1,
  resultado.queries_unsplash.query_imagem_2,
  resultado.queries_unsplash.query_imagem_3,
  resultado.queries_unsplash.query_imagem_4,
  resultado.queries_unsplash.query_imagem_5,
  resultado.queries_unsplash.query_imagem_6
];

// --- Retorna estrutura unificada e compatível ---
return [{
  json: {
    // Dados do post original
    id_post: $('Filtra Primeiro Post Aguardando').item.json.id_post,
    Titulo: $('Filtra Primeiro Post Aguardando').item.json.Titulo,

    // Estrutura completa da IA
